/* journey-db.js — dynamic card loader for the About/Journey section
 * Fetches Journey/manifest.json (generated by scripts/scan-journey.js).
 * Journey cards are static (no overlay) — rendered as <article> elements.
 * Add a NN_Title.md file to Journey/ and re-run the scan script to add a
 * new milestone card automatically.
 */
'use strict';

document.addEventListener('DOMContentLoaded', function () {
    var list = document.getElementById('journey-card-list');
    if (!list) return;

    fetch('data/Journey/manifest.json')
        .then(function (r) {
            return r.ok ? r.json() : Promise.reject(r.status);
        })
        .then(function (milestones) {
            list.innerHTML = milestones
                .map(function (m) {
                    var tagsHtml = (m.tags || [])
                        .map(function (t) {
                            return '<li class="tag">' + t + '</li>';
                        })
                        .join('');
                    return (
                        '<li>' +
                        '<article class="card card--static">' +
                        '<span class="card__num">' +
                        m.num +
                        '</span>' +
                        '<div class="card__body">' +
                        '<h3 class="card__title">' +
                        m.title +
                        '</h3>' +
                        '<p class="card__brief">' +
                        m.brief +
                        '</p>' +
                        '<ul class="card__tags">' +
                        tagsHtml +
                        '</ul>' +
                        '</div>' +
                        '</article>' +
                        '</li>'
                    );
                })
                .join('');

            requestAnimationFrame(function () {
                list.classList.add('is-visible');
            });
        })
        .catch(function (err) {
            list.innerHTML =
                '<li style="padding:20px;color:var(--text-3)">' +
                'Journey manifest could not be loaded (' +
                err +
                '). ' +
                'Run <code>node scripts/scan-journey.js</code>.' +
                '</li>';
            requestAnimationFrame(function () {
                list.classList.add('is-visible');
            });
        });
});
